import { Component, OnInit } from '@angular/core';
import { MedicalService } from '../../services/medical.service';
import { MedicalRecord } from '../../core/data.models';
import { Observable } from 'rxjs';

@Component({
  selector: 'app-medical-list',
  templateUrl: './medical-list.component.html'
})
export class MedicalListComponent implements OnInit {
  items$: Observable<MedicalRecord[]>;

  constructor(private svc: MedicalService) {
    this.items$ = this.svc.list$;
  }

  ngOnInit(): void {}

  remove(id: string) {
    this.svc.remove(id);
  }
}
<div class="header">
  <h2>Medical</h2>
  <button class="btn" routerLink="new">Add</button>
</div>

<div class="grid">
  <ng-container *ngIf="items$ | async as list">
    <div *ngIf="list.length === 0" class="card">No medical records. Click Add to create one.</div>
    <div *ngFor="let m of list" class="card">
      <h3>{{m.person}}</h3>
      <div class="small">{{m.type}}</div>
      <div style="margin-top:8px">Date: {{m.date || '—'}} | Provider: {{m.provider || '—'}}</div>
      <div style="margin-top:8px">
        <a [routerLink]="[m.id]">View</a>
        <a [routerLink]="[m.id, 'edit']" style="margin-left:8px">Edit</a>
        <button style="margin-left:8px" (click)="remove(m.id)">Delete</button>
      </div>
    </div>
  </ng-container>
</div>
